import React, { useEffect, useState, useContext, useRef } from 'react';
import { AuthContext } from '../contexts/AuthContext';
import { useNavigate } from 'react-router-dom';
import { io } from 'socket.io-client';
import JoinModal from './JoinModal';

const API_URL = 'http://localhost:3001';

export default function Lobby() {
  const { token, user, refreshUser } = useContext(AuthContext);
  const navigate = useNavigate();
  const socketRef = useRef(null);
  const [rooms, setRooms] = useState([]);
  const [myContests, setMyContests] = useState([]);
  const [liveContests, setLiveContests] = useState([]);
  const [message, setMessage] = useState('');
  const [msgType, setMsgType] = useState('');
  const [activeTab, setActiveTab] = useState('play');
  const [joinTarget, setJoinTarget] = useState(null);
  const [joining, setJoining] = useState(false);

  // Quick Match state
  const [isSearching, setIsSearching] = useState(false);
  const [selectedTC, setSelectedTC] = useState(3);
  const [searchTime, setSearchTime] = useState(0);

  // Completed match expand
  const [expandedMatch, setExpandedMatch] = useState(null);

  const fetchRooms = async () => {
    if (!token) return;
    try {
      const res = await fetch(`${API_URL}/api/rooms`, { headers: { Authorization: `Bearer ${token}` } });
      if (res.ok) setRooms(await res.json());
    } catch (e) { console.error('fetchRooms error', e); }
  };
  const fetchMyContests = async () => {
    if (!token) return;
    try {
      const res = await fetch(`${API_URL}/api/rooms/my-contests`, { headers: { Authorization: `Bearer ${token}` } });
      if (res.ok) setMyContests(await res.json());
    } catch (e) { console.error('fetchMyContests error', e); }
  };
  const fetchLiveContests = async () => {
    if (!token) return;
    try {
      const res = await fetch(`${API_URL}/api/rooms/live`, { headers: { Authorization: `Bearer ${token}` } });
      if (res.ok) setLiveContests(await res.json());
    } catch (e) { console.error('fetchLiveContests error', e); }
  };

  useEffect(() => {
    fetchRooms(); fetchMyContests(); fetchLiveContests();
    const interval = setInterval(() => { fetchRooms(); fetchMyContests(); fetchLiveContests(); }, 5000);
    return () => clearInterval(interval);
  }, [token]);

  // Socket for matchmaking
  useEffect(() => {
    if (!user?.id) return;
    if (!socketRef.current) socketRef.current = io(API_URL);
    const socket = socketRef.current;

    socket.emit('identify', { userId: user.id });

    socket.on('matchFound', (data) => {
      setIsSearching(false);
      setSearchTime(0);
      navigate(`/room/${data.roomId}`);
    });

    socket.on('queueJoined', () => {});
    socket.on('queueLeft', () => { setIsSearching(false); setSearchTime(0); });

    return () => {
      if (socketRef.current) {
        socketRef.current.removeAllListeners();
      }
    };
  }, [user?.id]);

  // Search timer
  useEffect(() => {
    if (!isSearching) return;
    const iv = setInterval(() => setSearchTime(t => t + 1), 1000);
    return () => clearInterval(iv);
  }, [isSearching]);

  const handlePlayNow = () => {
    if (isSearching) {
      // Cancel
      socketRef.current?.emit('leaveQueue', { userId: user.id, timeControl: selectedTC });
      setIsSearching(false);
      setSearchTime(0);
      return;
    }
    socketRef.current?.emit('joinQueue', { userId: user.id, timeControl: selectedTC });
    setIsSearching(true);
    setSearchTime(0);
  };

  const joinRoom = async () => {
    if (!joinTarget) return;
    try {
      setJoining(true);
      const res = await fetch(`${API_URL}/api/rooms/join`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({ roomId: joinTarget._id }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.message || 'Join failed');
      await refreshUser();
      setJoinTarget(null);
      navigate(`/room/${joinTarget.roomId}`);
    } catch (err) {
      setMessage(err.message); setMsgType('error');
      setTimeout(() => setMessage(''), 5000);
    } finally { setJoining(false); }
  };

  const completedContests = myContests.filter(r => r.status === 'completed');
  const activeContests = myContests.filter(r => r.status !== 'completed');

  const tabs = [
    { key: 'play', label: 'Play', icon: '⚡' },
    { key: 'open', label: 'Contests', icon: '🏟️', count: rooms.filter(r => r.status === 'waiting' && r.players.length < r.maxPlayers).length },
    { key: 'my', label: 'My Games', icon: '👤', count: activeContests.length },
    { key: 'live', label: 'Live', icon: '🔴', count: liveContests.length },
    { key: 'completed', label: 'History', icon: '✅', count: completedContests.length },
  ];

  const timeControls = [
    { tc: 1, label: '1 min', desc: 'Bullet', icon: '⚡' },
    { tc: 3, label: '3 min', desc: 'Blitz', icon: '🔥' },
    { tc: 5, label: '5 min', desc: 'Rapid', icon: '⏱️' },
  ];

  const formatDate = (date) => {
    const d = new Date(date);
    const now = new Date();
    const diff = now - d;
    if (diff < 86400000 && d.getDate() === now.getDate()) return 'Today';
    if (diff < 172800000) return 'Yesterday';
    if (diff < 604800000) return 'This Week';
    return d.toLocaleDateString();
  };

  return (
    <div className="min-h-screen bg-hero">
      <div className="max-w-7xl mx-auto px-4 py-6">
        {/* Hero */}
        <div className="mb-8 animate-fade-in">
          <h1 className="text-3xl sm:text-4xl font-black tracking-tight text-white mb-1">
            Chess <span className="text-gradient-green">Arena</span>
          </h1>
          <p className="text-slate-400 text-sm">Play, compete, and win real prizes</p>
        </div>

        {message && (
          <div className={`mb-6 p-4 rounded-xl border animate-slide-down ${
            msgType === 'success' ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400' : 'bg-red-500/10 border-red-500/20 text-red-400'
          }`}>{message}</div>
        )}

        {/* Tabs */}
        <div className="flex gap-1 bg-navy-800/50 backdrop-blur-sm rounded-xl p-1 mb-6 overflow-x-auto">
          {tabs.map(tab => (
            <button key={tab.key} onClick={() => setActiveTab(tab.key)}
              className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-medium whitespace-nowrap transition-all ${
                activeTab === tab.key ? 'bg-gradient-to-r from-chess-green/15 to-emerald-500/10 text-chess-green shadow-sm border border-chess-green/10' : 'text-slate-400 hover:text-white hover:bg-white/5'
              }`}>
              <span>{tab.icon}</span> {tab.label}
              {tab.count > 0 && (
                <span className={`px-1.5 py-0.5 rounded-full text-[10px] font-bold ${
                  activeTab === tab.key ? 'bg-chess-green/20 text-chess-green' : 'bg-navy-700 text-slate-500'
                }`}>{tab.count}</span>
              )}
            </button>
          ))}
        </div>

        {/* ============ PLAY NOW TAB ============ */}
        {activeTab === 'play' && (
          <div className="max-w-lg mx-auto animate-fade-in">
            <div className="card p-6 text-center">
              <h2 className="text-xl font-bold text-white mb-1">Quick Match</h2>
              <p className="text-sm text-slate-400 mb-6">Find an opponent instantly</p>

              {/* Time Control Selector */}
              <div className="flex gap-2 mb-6">
                {timeControls.map(tc => (
                  <button key={tc.tc} onClick={() => { if (!isSearching) setSelectedTC(tc.tc); }}
                    className={`flex-1 p-3 rounded-xl border-2 transition-all ${
                      selectedTC === tc.tc
                        ? 'border-chess-green bg-chess-green/10 shadow-lg shadow-chess-green/10'
                        : 'border-navy-700/30 hover:border-navy-600'
                    }`}>
                    <span className="text-xl mb-1 block">{tc.icon}</span>
                    <p className={`text-lg font-black ${selectedTC === tc.tc ? 'text-chess-green' : 'text-white'}`}>{tc.label}</p>
                    <p className="text-[10px] text-slate-500">{tc.desc}</p>
                  </button>
                ))}
              </div>

              {/* Search Status */}
              {isSearching && (
                <div className="mb-4 p-4 rounded-xl bg-chess-green/5 border border-chess-green/20 animate-fade-in">
                  <div className="flex items-center gap-3 justify-center mb-2">
                    <div className="w-6 h-6 border-2 border-chess-green border-t-transparent rounded-full animate-spin" />
                    <p className="text-chess-green font-bold">Finding opponent...</p>
                  </div>
                  <p className="text-slate-500 text-xs">{searchTime}s elapsed</p>
                  <div className="mt-2 flex justify-center gap-1">
                    {[0,1,2].map(i => (
                      <div key={i} className="w-2 h-2 rounded-full bg-chess-green/50 animate-pulse" style={{ animationDelay: `${i * 200}ms` }} />
                    ))}
                  </div>
                </div>
              )}

              {/* Play Now Button */}
              <button onClick={handlePlayNow}
                className={`w-full py-4 rounded-xl text-lg font-black transition-all ${
                  isSearching
                    ? 'bg-red-600 hover:bg-red-500 text-white'
                    : 'bg-gradient-to-r from-chess-green to-emerald-600 hover:from-chess-green hover:to-emerald-500 text-white shadow-lg shadow-chess-green/25 hover:shadow-chess-green/40 active:scale-[0.98]'
                }`}>
                {isSearching ? '✕ Cancel Search' : `⚡ Play Now — ${selectedTC} min`}
              </button>

              <p className="text-[10px] text-slate-600 mt-3">Free to play • ELO rated</p>
            </div>
          </div>
        )}

        {/* ============ OPEN CONTESTS ============ */}
        {activeTab === 'open' && (
          rooms.filter(r => r.status === 'waiting' && r.players.length < r.maxPlayers).length === 0 ? (
            <div className="card text-center py-16 animate-fade-in">
              <div className="text-5xl mb-4">🏗️</div>
              <p className="text-slate-400 font-medium">No contests available</p>
              <p className="text-slate-500 text-sm mt-1">Check back later!</p>
            </div>
          ) : (
            <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {rooms.filter(r => r.status === 'waiting' && r.players.length < r.maxPlayers).map((r, idx) => (
                <ContestCard key={r.roomId} room={r} user={user} onJoin={() => setJoinTarget(r)} onEnter={() => navigate(`/room/${r.roomId}`)} delay={idx * 50} />
              ))}
            </div>
          )
        )}

        {/* ============ MY CONTESTS ============ */}
        {activeTab === 'my' && (
          activeContests.length === 0 ? (
            <div className="card text-center py-16 animate-fade-in">
              <div className="text-5xl mb-4">📭</div>
              <p className="text-slate-400 font-medium">No active contests</p>
            </div>
          ) : (
            <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {activeContests.map((r, idx) => (
                <ContestCard key={r.roomId} room={r} user={user} onJoin={() => setJoinTarget(r)} onEnter={() => navigate(`/room/${r.roomId}`)} delay={idx * 50} />
              ))}
            </div>
          )
        )}

        {/* ============ LIVE ============ */}
        {activeTab === 'live' && (
          liveContests.length === 0 ? (
            <div className="card text-center py-16 animate-fade-in">
              <div className="text-5xl mb-4">⏳</div>
              <p className="text-slate-400 font-medium">No live contests right now</p>
            </div>
          ) : (
            <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {liveContests.map((r, idx) => (
                <ContestCard key={r.roomId} room={r} user={user} onJoin={() => setJoinTarget(r)} onEnter={() => navigate(`/room/${r.roomId}`)} delay={idx * 50} />
              ))}
            </div>
          )
        )}

        {/* ============ COMPLETED ============ */}
        {activeTab === 'completed' && (
          completedContests.length === 0 ? (
            <div className="card text-center py-16 animate-fade-in">
              <div className="text-5xl mb-4">🎮</div>
              <p className="text-slate-400 font-medium">No completed matches yet</p>
              <p className="text-slate-500 text-sm mt-1">Play a match to see history!</p>
            </div>
          ) : (
            <div className="space-y-2 animate-fade-in">
              {/* Group by date */}
              {(() => {
                const groups = {};
                completedContests.forEach(r => {
                  const dateKey = formatDate(r.createdAt);
                  if (!groups[dateKey]) groups[dateKey] = [];
                  groups[dateKey].push(r);
                });
                return Object.entries(groups).map(([date, items]) => (
                  <div key={date}>
                    <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-2 mt-3">{date}</h3>
                    <div className="space-y-1.5">
                      {items.map(r => {
                        const myMatch = r.matches?.find(m =>
                          m.player1?.toString() === user?.id || m.player2?.toString() === user?.id ||
                          m.player1?._id?.toString() === user?.id || m.player2?._id?.toString() === user?.id
                        );
                        const isWinner = myMatch?.winner?.toString() === user?.id || myMatch?.winner?._id?.toString() === user?.id;
                        const isDraw = myMatch && !myMatch.winner;
                        const isExpanded = expandedMatch === r.roomId;

                        return (
                          <div key={r.roomId}>
                            <button
                              onClick={() => setExpandedMatch(isExpanded ? null : r.roomId)}
                              className="w-full flex items-center gap-3 p-3 rounded-xl bg-navy-800/50 border border-navy-700/20 hover:border-navy-600/30 transition-all text-left"
                            >
                              <span className="text-lg flex-shrink-0">♟</span>
                              <span className="text-sm text-white font-medium flex-1 truncate">{r.name || r.roomId}</span>
                              <span className={`text-xs font-bold px-2 py-0.5 rounded-full ${
                                isWinner ? 'bg-chess-green/15 text-chess-green' : isDraw ? 'bg-slate-500/15 text-slate-400' : 'bg-red-500/15 text-red-400'
                              }`}>
                                {isWinner ? 'Won' : isDraw ? 'Draw' : 'Lost'}
                              </span>
                              {r.entryFee > 0 && isWinner && (
                                <span className="text-xs text-gold-400 font-bold">+₹{(r.entryFee * r.maxPlayers * 0.7).toFixed(0)}</span>
                              )}
                              <span className="text-[10px] text-slate-600">{new Date(r.createdAt).toLocaleDateString('en', { month: 'short', day: 'numeric' })}</span>
                              <span className="text-slate-500 text-xs">{isExpanded ? '▲' : '▼'}</span>
                            </button>

                            {isExpanded && (
                              <div className="mt-1 ml-8 p-3 rounded-xl bg-navy-800/30 border border-navy-700/10 animate-slide-down">
                                <div className="grid grid-cols-3 gap-3 text-xs mb-3">
                                  <div><span className="text-slate-500">Fee</span><p className="text-white font-bold">₹{r.entryFee}</p></div>
                                  <div><span className="text-slate-500">Players</span><p className="text-white font-bold">{r.maxPlayers}P</p></div>
                                  <div><span className="text-slate-500">Rounds</span><p className="text-white font-bold">{r.currentRound}</p></div>
                                </div>
                                <button onClick={() => navigate(`/room/${r.roomId}`)} className="btn-sm btn-secondary w-full">
                                  📊 View Details
                                </button>
                              </div>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                ));
              })()}
            </div>
          )
        )}
      </div>

      {joinTarget && (
        <JoinModal room={joinTarget} onConfirm={joinRoom} onClose={() => setJoinTarget(null)} loading={joining} />
      )}
    </div>
  );
}

function ContestCard({ room, user, onJoin, onEnter, delay }) {
  const prizePool = room.entryFee * room.maxPlayers;
  const fillPercent = (room.players.length / room.maxPlayers) * 100;
  const hasJoined = room.players.some(p => (p._id || p).toString() === user?.id?.toString());
  const isWaiting = room.status === 'waiting';
  const isOngoing = room.status === 'ongoing';
  const isCompleted = room.status === 'completed';
  const isFull = room.players.length >= room.maxPlayers;

  return (
    <div className="contest-card animate-slide-up" style={{ animationDelay: `${delay}ms` }}>
      <div className="flex items-start justify-between mb-4">
        <div>
          <h3 className="text-sm font-bold text-white mb-0.5">{room.name || room.roomId}</h3>
          <p className="text-xs text-slate-500">{room.roomId}</p>
        </div>
        <div>
          {isWaiting && !isFull && <span className="badge-green">Open</span>}
          {isWaiting && isFull && <span className="badge bg-orange-500/15 text-orange-400 border border-orange-500/20">Full</span>}
          {isOngoing && <span className="badge-gold"><span className="w-1.5 h-1.5 rounded-full bg-gold-400 animate-pulse" />Live</span>}
          {isCompleted && <span className="badge bg-slate-700/50 text-slate-400 border-slate-600/30">Ended</span>}
        </div>
      </div>
      <div className="mb-4 p-3 rounded-xl bg-navy-900/50 border border-navy-700/20">
        <div className="flex items-center justify-between">
          <div><p className="text-[10px] font-medium text-slate-500 uppercase tracking-wider">Prize Pool</p><p className="text-2xl font-black text-white">₹{prizePool.toLocaleString()}</p></div>
          <div className="text-right"><p className="text-[10px] font-medium text-slate-500 uppercase tracking-wider">Entry</p><p className="text-lg font-bold text-gold-400">₹{room.entryFee}</p></div>
        </div>
      </div>
      <div className="flex items-center justify-between mb-3">
        <span className={`badge ${room.prizeDistribution === 'winnerTA' ? 'badge-gold' : 'badge-blue'}`}>
          {room.prizeDistribution === 'winnerTA' ? '🏆 Winner Takes All' : '🎯 Top 4'}
        </span>
        <span className="text-xs font-medium text-slate-400">{room.players.length}/{room.maxPlayers} joined</span>
      </div>
      <div className="mb-4">
        <div className="progress-bar">
          <div className={`progress-fill ${fillPercent >= 100 ? 'bg-orange-500' : fillPercent >= 80 ? 'bg-gradient-to-r from-red-500 to-orange-500' : fillPercent >= 50 ? 'bg-gradient-to-r from-gold-500 to-orange-400' : 'bg-gradient-to-r from-chess-green to-emerald-400'}`}
            style={{ width: `${fillPercent}%` }} />
        </div>
        {fillPercent >= 80 && isWaiting && !isFull && (
          <p className="text-[10px] text-red-400 mt-1">⚡ {room.maxPlayers - room.players.length} spot{room.maxPlayers - room.players.length > 1 ? 's' : ''} left</p>
        )}
      </div>
      {isWaiting && !hasJoined && !isFull && <button onClick={onJoin} className="btn-primary w-full">Join Now — ₹{room.entryFee}</button>}
      {isWaiting && !hasJoined && isFull && <button disabled className="btn-secondary w-full opacity-50 cursor-not-allowed">Contest Full</button>}
      {hasJoined && isWaiting && <button onClick={onEnter} className="btn-secondary w-full">✓ Joined — Enter Room</button>}
      {(isOngoing || isCompleted) && hasJoined && <button onClick={onEnter} className="btn-primary w-full">{isOngoing ? '⚡ Enter Match' : '📊 View Results'}</button>}
      {(isOngoing || isCompleted) && !hasJoined && <button onClick={onEnter} className="btn-ghost w-full border border-navy-700/50">👁️ Spectate</button>}
    </div>
  );
}
